{
    int minSad = Integer.MAX_VALUE;
    int dInd = BLK_DISP_MAP[bInd];
    boolean hasLeft = (dInd & 0x3) != 0 || mbX != 0;
    boolean hasTop = dInd >= 4 || mbY != 0;
    boolean hasTr = ((bInd == 0 || bInd == 1 || bInd == 4) && mbY != 0) || (bInd == 5 && mbX < ctx.mbWidth - 1) || bInd == 2 || bInd == 6 || bInd == 8 || bInd == 9 || bInd == 10 || bInd == 12 || bInd == 14;
    predModes[bInd] = 2;
    int blkX = (dInd & 0x3) << 2;
    int blkY = (dInd >> 2) << 2;

    if (hasLeft) {
        predLeft[blkY] = (byte) clip(bresi[3] + bpred[3], -128, 127);
        predLeft[blkY + 1] = (byte) clip(bresi[7] + bpred[7], -128, 127);
        predLeft[blkY + 2] = (byte) clip(bresi[11] + bpred[11], -128, 127);
