        int blkY = (dInd >> 2) << 2;
        for (int predType = 0; predType < 9; predType++) {
            boolean available = Intra4x4PredictionBuilder.lumaPred(predType, hasLeft, hasTop, hasTr, predLeft, predTop, predTopLeft[dInd >> 2], blkX, blkY, pred);
            if (available) {
                int sad = 0;
